SELECT SUM(murder_manslaughter) AS total_murders_manslaughters
FROM state_crime_data
WHERE state_name = 'New York' AND year = 2015;

SELECT state_name
FROM state_crime_data
WHERE population = (
  SELECT MAX(population)
  FROM state_crime_data
);

SELECT state_name, violent_crime_rate 
FROM state_crime_data 
WHERE violent_crime_rate = (SELECT MAX(violent_crime_rate) FROM state_crime_data);

SELECT SUM(murder_manslaughter) AS total_murders_manslaughters
FROM state_crime_data
WHERE state_id = 1;

SELECT AVG(total_crime_rate) AS average_crime_rate_across_all_years
FROM state_crime_data
WHERE state_id = 0;

SELECT SUM(CASE WHEN clearance_status = 'Solved' THEN 1 ELSE 0 END) AS solved_crimes
FROM state_crime_data
WHERE state_id = 1 AND year = 1 AND crime_status = 'Closed';

SELECT SUM(CASE WHEN victim_status = 'Deceased' THEN 1 ELSE 0 END) AS total_deceased_victims
FROM crime_victims
WHERE year > 2015;
